{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラの正式キックオフを発足と決定し、走り出しを行う。",
      "decided_by": "桐生遥"
    },
    {
      "id": "D2",
      "content": "本番リリースの目標を9月末から10月15日に撤回して決まることを決定する。",
      "decided_by": "桐生遥"
    },
    {
      "id": "D3",
      "content": "移行方式として、芦田 巧さんの提案した段階的切り替え（拠点をグループ分けして順次行う）を確定させる。",
      "decided_by": "桐生遥"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "API仕様書のドラフトを作成する（主要な項目のレイアウトを含める）",
      "assignee": "芦田巧",
      "due": "2026-05-20"
    },
    {
      "id": "A2",
      "task": "検証環境用サーバを調達する（現行の6台から倍増し3台削る構成で）",
      "assignee": "沼田賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "現場ヒアリングの対象部署リストを作成する（担当者の名前も記載して）",
      "assignee": "東雲美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A4",
      "task": "外部ライセンス費用の再見積もりを作成する（年契約条件も併せて）",
      "assignee": "郡司明久",
      "due": "2026-06-01"
    },
    {
      "id": "A5",
      "task": "サクラ商事への共同利用の回答書を作成・送付する（技術的な条件箇所のみ埋める）",
      "assignee": "桐生遥",
      "due": "2026-05-19"
    },
    {
      "id": "A6",
      "task": "移行テスト計画を作成し提出する（全件数と主要マスタの整合性を保証して）",
      "assignee": "芦田巧",
      "due": "2026-06-03"
    },
    {
      "id": "A7",
      "task": "負荷テスト計画を作成し提出する（測定点を社内ネットワーク側で切る前提で）",
      "assignee": "白鳥千夏",
      "due": "2026-06-03"
    },
    {
      "id": "A8",
      "task": "移行リハーサルの手順書を作成する（作業の実体を沼田 賢一さんに依頼して、白鳥さんにもレビューを得る）",
      "assignee": "沼田賢一",
      "due": "2026-06-05"
    },
    {
      "id": "A9",
      "task": "各拠点の生産管理担当者との説明会日程調整を行う（一日で完結はしない場合もある）",
      "assignee": "東雲美咲",
      "due": "2026-05-27"
    }
  ],
  "key_numbers": [
    {
      "id": "N1",
      "label": "対象拠点数と想定利用者数の合計規模（ログインして在庫操作を行う人）",
      "value": "320人"
    },
    {
      "id": "N2",
      "label": "現行システムの月平均ダウンタイム時間（バッチ待ちなどによる業務停止を含む）",
      "value": "42分/月"
    },
    {
      "id": "N3",
      "label": "新システムの実装目標応答時間の上限値（画面操作から描画完了まで、通信込みの標準値）",
      "value": "1.2秒以内"
    },
    {
      "id": "N4",
      "label": "移行方式選択に伴う切り替え所要時間の上限目安（安定を確認する待ち時間を含めた最小単位）",
      "value": "2週間/グループ"
    }
  ]
}
